// ds_330_FillUse → ds_results 복사 + 검증
scwin.f_Upload = function () {
  ds_results.removeAll();
  let altMsg = "";
  let totalCnt = ds_330_FillUse.getRowCount();
  for (let i = 0; i < totalCnt; i++) {
    if (!ds_330_FillUse.getCellData(i, "rsltsStdDt")) continue;
    let nRow = ds_results.insertRow();
    ds_results.setCellData(nRow, "rsltsStdDt", ds_330_FillUse.getCellData(i, "rsltsStdDt"));
    ds_results.setCellData(nRow, "vehclNo", ds_330_FillUse.getCellData(i, "vehclNo"));
    ds_results.setCellData(nRow, "homeClntNo", ds_330_FillUse.getCellData(i, "homeClntNo"));
    ds_results.setCellData(nRow, "clntNo", ds_330_FillUse.getCellData(i, "clntNo"));
    ds_results.setCellData(nRow, "clntNm", ds_330_FillUse.getCellData(i, "clntNm"));
    ds_results.setCellData(nRow, "amt01", ds_330_FillUse.getCellData(i, "amt01"));
    ds_results.setCellData(nRow, "amt02", ds_330_FillUse.getCellData(i, "amt02"));
    ds_results.setCellData(nRow, "amt03", ds_330_FillUse.getCellData(i, "amt03"));
    ds_results.setCellData(nRow, "amt04", ds_330_FillUse.getCellData(i, "amt04"));
    ds_results.setCellData(nRow, "amt05", ds_330_FillUse.getCellData(i, "amt05"));
    ds_results.setCellData(nRow, "amt06", ds_330_FillUse.getCellData(i, "amt06"));
    ds_results.setCellData(nRow, "amt07", ds_330_FillUse.getCellData(i, "amt07"));
    ds_results.setCellData(nRow, "amt08", ds_330_FillUse.getCellData(i, "amt08"));
    ds_results.setCellData(nRow, "amt09", ds_330_FillUse.getCellData(i, "amt09"));
    ds_results.setCellData(nRow, "amt10", ds_330_FillUse.getCellData(i, "amt10"));
    ds_results.setCellData(nRow, "amt11", ds_330_FillUse.getCellData(i, "amt11"));
    ds_results.setCellData(nRow, "amt12", ds_330_FillUse.getCellData(i, "amt12"));
    ds_results.setCellData(nRow, "amt13", ds_330_FillUse.getCellData(i, "amt13"));
    ds_results.setCellData(nRow, "amt14", ds_330_FillUse.getCellData(i, "amt14"));
    ds_results.setCellData(nRow, "amt15", ds_330_FillUse.getCellData(i, "amt15"));
    ds_results.setCellData(nRow, "amt16", ds_330_FillUse.getCellData(i, "amt16"));
    ds_results.setCellData(nRow, "amt17", ds_330_FillUse.getCellData(i, "amt17"));
    ds_results.setCellData(nRow, "amt18", ds_330_FillUse.getCellData(i, "amt18"));
    ds_results.setCellData(nRow, "amt19", ds_330_FillUse.getCellData(i, "amt19"));
    ds_results.setCellData(nRow, "etc01", ds_330_FillUse.getCellData(i, "etc01"));
    ds_results.setCellData(nRow, "etc02", ds_330_FillUse.getCellData(i, "etc02"));
    ds_results.setCellData(nRow, "etc03", ds_330_FillUse.getCellData(i, "etc03"));
    ds_results.setCellData(nRow, "etc04", ds_330_FillUse.getCellData(i, "etc04"));
    ds_results.setCellData(nRow, "etc05", ds_330_FillUse.getCellData(i, "etc05"));
    ds_results.setCellData(nRow, "etc06", ds_330_FillUse.getCellData(i, "etc06"));
    ds_results.setCellData(nRow, "etc07", ds_330_FillUse.getCellData(i, "etc07"));
    ds_results.setCellData(nRow, "etc08", ds_330_FillUse.getCellData(i, "etc08"));
    ds_results.setCellData(nRow, "etc09", ds_330_FillUse.getCellData(i, "etc09"));
    ds_results.setCellData(nRow, "etc10", ds_330_FillUse.getCellData(i, "etc10"));
    ds_results.setCellData(nRow, "etc11", ds_330_FillUse.getCellData(i, "etc11"));
    ds_results.setCellData(nRow, "etc12", ds_330_FillUse.getCellData(i, "etc12"));
    ds_results.setCellData(nRow, "etc13", ds_330_FillUse.getCellData(i, "etc13"));
    ds_results.setCellData(nRow, "etc14", ds_330_FillUse.getCellData(i, "etc14"));
    ds_results.setCellData(nRow, "etc15", ds_330_FillUse.getCellData(i, "etc15"));
    ds_results.setCellData(nRow, "etc16", ds_330_FillUse.getCellData(i, "etc16"));
    ds_results.setCellData(nRow, "etc17", ds_330_FillUse.getCellData(i, "etc17"));

    // amt10 vs etc01~17 합산 검증
    let amt10 = Number(ds_330_FillUse.getCellData(i, "amt10")) || 0;
    let etcSum = 0;
    for (let n = 1; n <= 17; n++) {
      etcSum += Number(ds_330_FillUse.getCellData(i, "etc" + String(n).padStart(2, "0"))) || 0;
    }
    if (amt10 != etcSum) {
      if (altMsg !== "") altMsg += ", ";
      altMsg += nRow + 1;
    }
  }
  ds_330_FillUse.removeAll();
  if (altMsg !== "") {
    $c.win.alert($p, altMsg + "행의 기타매출액과 기타매출상세의 합이 일치하지 않습니다.");
  }
  totalRows.setValue(ds_results.getRowCount());
};

// 엑셀 다운로드 
scwin.f_downloadsExcel = function () {
  let grdObj = gr_results;
  let options = {
    fileName: "운송임및비용등록.xlsx",
    sheetName: "운송임및비용등록"
  };
  let infoArr = {};
  // AS-IS: 조회 결과 없어도 엑셀 다운로드
  $c.data.downloadGridViewExcel($p, grdObj, options, infoArr, 8 + 16);
};

//-------------------------------------------------------------------------
// function name : f_Apply
// function desc : 적용 
//-------------------------------------------------------------------------
scwin.btn_apply_onclick = async function (e) {
  let checkedCnt = 0;
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    //INSERT
    if (ds_results.getRowStatusValue(i) == "1") {
      //Gaus -> 3:update / WebSquare -> 1: 갱신
      if (ds_results.getCellData(i, "uploadNo") == "") {
        $c.win.alert($p, "업로드 후 적용해주세요");
        return;
      }
      if (ds_results.getCellData(i, "rsltsMgntNo") != "") {
        $c.win.alert($p, "적용된 데이터는 재 적용할 수 없습니다.");
        return;
      }
      checkedCnt++;
    }
  } //for

  if (checkedCnt == 0) {
    $c.win.alert($p, "적용 할 데이터가 없습니다.");
    return false;
  }
  let confirm = await $c.win.confirm($p, "업로드 한 운송임을 등록하시겠습니까?");
  if (confirm) {
    //tr_apply.Post();
    $c.sbm.execute($p, sbm_apply);
  }
};
scwin.sbm_apply_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_002); // 성공적으로 등록하였습니다.
    scwin.btn_retrieve_onclick();
  }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
  let checkedCnt = 0;
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    //INSERT
    if (ds_results.getRowStatusValue(i) == "2") {
      // 신규 생성
      //if(!cfValidateValue(ds_results.getCellData(i, "rsltsStdDt"), "date=YYYYMMDD")) {
      if (!$c.date.isDate($p, ds_results.getCellData(i, "rsltsStdDt"))) {
        $c.gus.cfAlertMsg($p, i + 1 + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
        return;
      }
      if (ds_results.getCellData(i, "rsltsStdDt") == "") {
        $c.win.alert($p, i + 1 + "행의 실적일자는 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_results.getCellData(i, "vehclNo") == "") {
        $c.win.alert($p, i + 1 + "행의 차량번호는 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_results.getCellData(i, "homeClntNo") == "") {
        $c.win.alert($p, i + 1 + "행의 소속거래처는 필수 입력 항목 입니다.");
        return false;
      }
      if (ds_results.getCellData(i, "clntNo") == "" && ds_results.getCellData(i, "clntNm") == "") {
        $c.win.alert($p, i + 1 + "행의 매니저코드/명  중 하나는 필수 입력 항목 입니다.");
        return false;
      }
      checkedCnt++;
    }
    //DELETE
    if (ds_results.getRowStatusValue(i) == "3") {
      // 삭제
      checkedCnt++;
    }
  } //for

  if (checkedCnt == 0) {
    $c.win.alert($p, "저장 할 데이터가 없습니다.");
    return false;
  }
  let confirm = await $c.win.confirm($p, MSG_CM_CRM_001); //저장하시겠습니까?
  if (confirm) {
    //tr_save.Post();
    $c.sbm.execute($p, sbm_save);
  }
};
scwin.sbm_save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    scwin.btn_retrieve_onclick();
  }
};

//-------------------------------------------------------------------------
// 행삭제
//------------------------------------------------------------------------- 
scwin.btn_delete_onclick = async function (e) {
  // 실적관리번호 체크// 2026-03-30[T-5935] 체크된 행만 삭제 검증 가능하도록 개선
  let checkedCount = 0;
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getCellData(i, "chk") != "1") continue;
    checkedCount++;
    if (ds_results.getCellData(i, "rsltsMgntNo") != "") {
      $c.win.alert($p, "적용 후 실적번호가 생성된경우 삭제할 수 없습니다.");
      return;
    }
  }
  if (checkedCount === 0) {
    $c.win.alert($p, "삭제할 데이터가 없습니다.");
    return;
  }
  let confirm = await $c.win.confirm($p, MSG_CM_CRM_004);
  if (!confirm) return;

  // 역방향 루프로 deleteRow (순방향은 index 밀림)
  for (let i = ds_results.getRowCount() - 1; i >= 0; i--) {
    if (ds_results.getCellData(i, "chk") == "1") {
      ds_results.deleteRow(i);
    }
  }
  $c.sbm.execute($p, sbm_delete);
};
scwin.sbm_delete_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_004); // 성공적으로 삭제하였습니다
    scwin.btn_retrieve_onclick();
  }
};
